/*
 * Power Usage Effectiveness (PUE) Calculator
 * Measures and analyzes data center energy efficiency
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_RECOMMENDATIONS 10

/* Structure to hold calculation results */
typedef struct {
    double pue;
    double totalPower;
    double itPower;
    double nonItOverhead;
    double overheadPercentage;
    char rating[50];
} PUEResult;

/* Structure for optimization recommendation */
typedef struct {
    char recommendation[100];
} OptimizationRec;

/* Calculate PUE and determine efficiency rating */
PUEResult calculate_pue(double total_power, double it_power) {
    PUEResult result;

    /* Validate inputs */
    if (total_power <= 0 || it_power <= 0) {
        printf("Error: Power values must be positive\n");
        result.pue = -1;
        return result;
    }

    /* Calculate PUE */
    result.pue = total_power / it_power;
    result.totalPower = total_power;
    result.itPower = it_power;

    /* Calculate non-IT overhead */
    result.nonItOverhead = total_power - it_power;
    result.overheadPercentage = (result.nonItOverhead / total_power) * 100.0;

    /* Determine efficiency rating */
    if (result.pue == 1.0) {
        strcpy(result.rating, "Perfect - All power for computing");
    } else if (result.pue < 1.2) {
        strcpy(result.rating, "Excellent - Highly efficient");
    } else if (result.pue < 1.5) {
        strcpy(result.rating, "Good - Typical efficient facility");
    } else if (result.pue < 2.0) {
        strcpy(result.rating, "Average - Room for improvement");
    } else {
        strcpy(result.rating, "Poor - High overhead");
    }

    return result;
}

/* Get optimization recommendations based on current PUE */
int get_recommendations(double pue, OptimizationRec recommendations[]) {
    int count = 0;

    if (pue > 1.5) {
        strcpy(recommendations[count++].recommendation, 
               "Implement hot aisle/cold aisle containment");
        strcpy(recommendations[count++].recommendation, 
               "Upgrade to energy-efficient servers (80+ Platinum)");
        strcpy(recommendations[count++].recommendation, 
               "Consider liquid cooling for high-density workloads");
    }

    if (pue > 1.3) {
        strcpy(recommendations[count++].recommendation, 
               "Deploy free cooling using external air");
        strcpy(recommendations[count++].recommendation, 
               "Implement server virtualization/consolidation");
    }

    if (pue > 1.2) {
        strcpy(recommendations[count++].recommendation, 
               "Install ML-based cooling optimization");
        strcpy(recommendations[count++].recommendation, 
               "Consider renewable energy sources");
    }

    return count;
}

/* Print PUE result in formatted output */
void print_result(PUEResult result) {
    printf("\n========================================\n");
    printf("DATA CENTER ENERGY EFFICIENCY REPORT\n");
    printf("========================================\n");
    printf("Total Facility Power:   %.2f kW\n", result.totalPower);
    printf("IT Equipment Power:     %.2f kW\n", result.itPower);
    printf("Non-IT Overhead:        %.2f kW (%.2f%%)\n", 
           result.nonItOverhead, result.overheadPercentage);
    printf("----------------------------------------\n");
    printf("PUE:                    %.3f\n", result.pue);
    printf("Efficiency Rating:      %s\n", result.rating);
    printf("========================================\n");
}

/* Calculate annual energy costs and carbon footprint */
void calculate_annual_impact(double total_power_kw, double pue) {
    double hours_per_year = 8760.0;  /* Non-leap year */
    double energy_cost_per_kwh = 0.12;  /* Average cost in USD */
    double carbon_per_kwh = 0.42;  /* kg CO2 per kWh (US average) */

    double annual_energy_kwh = total_power_kw * hours_per_year;
    double annual_cost = annual_energy_kwh * energy_cost_per_kwh;
    double annual_carbon_kg = annual_energy_kwh * carbon_per_kwh;
    double annual_carbon_tons = annual_carbon_kg / 1000.0;

    printf("\nAnnual Impact Estimates:\n");
    printf("  Energy Consumption: %.0f kWh\n", annual_energy_kwh);
    printf("  Estimated Cost:     $%.2f\n", annual_cost);
    printf("  Carbon Footprint:   %.2f tons CO2\n", annual_carbon_tons);

    /* Show improvement potential */
    if (pue > 1.2) {
        double ideal_energy = (total_power_kw / pue) * hours_per_year;
        double savings_kwh = annual_energy_kwh - ideal_energy;
        double savings_cost = savings_kwh * energy_cost_per_kwh;
        printf("\nPotential Savings with PUE 1.2:\n");
        printf("  Energy Saved:    %.0f kWh/year\n", savings_kwh);
        printf("  Cost Savings:    $%.2f/year\n", savings_cost);
    }
}

int main() {
    PUEResult result;
    OptimizationRec recommendations[MAX_RECOMMENDATIONS];
    int num_recommendations;

    /* Example 1: Typical enterprise data center */
    printf("\n=== Scenario 1: Typical Enterprise Data Center ===");
    result = calculate_pue(1000.0, 667.0);  /* PUE = 1.5 */
    print_result(result);

    num_recommendations = get_recommendations(result.pue, recommendations);
    printf("\nOptimization Recommendations:\n");
    for (int i = 0; i < num_recommendations; i++) {
        printf("  %d. %s\n", i + 1, recommendations[i].recommendation);
    }

    calculate_annual_impact(result.totalPower, result.pue);

    /* Example 2: Highly efficient (Google-level) */
    printf("\n\n=== Scenario 2: Highly Efficient Data Center ===");
    result = calculate_pue(1000.0, 900.0);  /* PUE = 1.11 */
    print_result(result);

    num_recommendations = get_recommendations(result.pue, recommendations);
    printf("\nOptimization Recommendations:\n");
    if (num_recommendations == 0) {
        printf("  No recommendations - excellent efficiency!\n");
    } else {
        for (int i = 0; i < num_recommendations; i++) {
            printf("  %d. %s\n", i + 1, recommendations[i].recommendation);
        }
    }

    return 0;
}
